Steps:
[AUTH role=USER2]
[GQL-OP setup_user2]
  query { me { id } }
[GQL-EXEC setup_user2]
[GQL-CAPTURE setup_user2.data.me.id → USER2_ID]
[GQL-OP cleanup_user2_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER2_ID}}" }) { id } }
[GQL-EXEC cleanup_user2_pre]
[GQL-OP get_def]
  query { productConfiguration(configurableProductId: "@td(CFG_LAPTOP.id)" storeId: "{{STORE_ID}}") { configurationSections { id options { product { id } } } } }
[GQL-EXEC get_def]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.id → SECTION_RAM_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.options.1.product.id → OPT_RAM_UPGRADE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.id → SECTION_STORAGE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.options.1.product.id → OPT_STORAGE_UPGRADE_ID]
[GQL-OP add_item_user2]
[GQL-VARS add_item_user2] {"configurationSections": [{"sectionId": "{{SECTION_RAM_ID}}", "type": "Product", "option": {"productId": "{{OPT_RAM_UPGRADE_ID}}", "quantity": 1}}, {"sectionId": "{{SECTION_STORAGE_ID}}", "type": "Product", "option": {"productId": "{{OPT_STORAGE_UPGRADE_ID}}", "quantity": 1}}]}
  mutation AddItem($configurationSections: [ConfigurationSectionInput]) {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER2_ID}}" productId: "@td(CFG_LAPTOP.id)" quantity: 1 configurationSections: $configurationSections }) {
      id itemsCount items { id productId configurationItems { id sectionId productId selectedForCheckout } }
    }
  }
[GQL-EXEC add_item_user2]
[GQL-OP get_source_cart]
  query { cart(storeId: "{{STORE_ID}}" currencyCode: "USD" userId: "{{USER2_ID}}") { id } }
[GQL-EXEC get_source_cart]
[GQL-CAPTURE get_source_cart.data.cart.id → SOURCE_CART_ID]
[AUTH role=ORG_USER]
[GQL-OP setup_org_user]
  query { me { id } }
[GQL-EXEC setup_org_user]
[GQL-CAPTURE setup_org_user.data.me.id → USER_ID]
[GQL-OP cleanup_org_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_org_pre]
[GQL-OP merge]
  mutation {
    mergeCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cartId: "{{SOURCE_CART_ID}}" currencyCode: "USD" }) {
      id itemsCount items { id productId configurationItems { id sectionId productId selectedForCheckout } }
    }
  }
[GQL-EXEC merge]
[GQL-OP read_back]
  query { cart(storeId: "{{STORE_ID}}" currencyCode: "USD" userId: "{{USER_ID}}") { id itemsCount items { id productId configurationItems { id sectionId productId selectedForCheckout } } } }
[GQL-EXEC read_back]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]
[AUTH role=USER2]
[GQL-OP cleanup_user2_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER2_ID}}" }) { id } }
[GQL-EXEC cleanup_user2_post]

